{"file_path": "/home/leul/Documents/task-7/repo/studioops/app/templates/base.html", "content": "<!DOCTYPE html>
<html lang="en" class="h-full bg-stone-50">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>{% block title %}StudioOps{% endblock %}</title>

  <!-- Tailwind CSS CDN -->
  <script src="https://cdn.tailwindcss.com"></script>
  <script>
    tailwind.config = {
      theme: {
        extend: {
          colors: {
            brand: {
              50:  '#f5f3ff',
              100: '#ede9fe',
              500: '#8b5cf6',
              600: '#7c3aed',
              700: '#6d28d9',
            }
          }
        }
      }
    }
  </script>

  <!-- HTMX 2.x -->
  <script src="https://unpkg.com/htmx.org@2.0.4" integrity="sha384-HGfztofotfshcF7+8n44JQL2oJmowVChPTg48S+jvZoztPfvwD79OC/LTtG6dMp+" crossorigin="anonymous"></script>

  <!-- CSRF meta tag for HTMX -->
  <meta name="csrf-token" content="{{ csrf_token() }}" />
  <script>
    document.addEventListener('htmx:configRequest', (e) => {
      e.detail.headers['X-CSRFToken'] = document.querySelector('meta[name="csrf-token"]').content;
    });
  </script>

  <link rel="stylesheet" href="{{ url_for('static', filename='css/custom.css') }}" />
  {% block head %}{% endblock %}
</head>

<body class="h-full flex flex-col" hx-boost="false">

  <!-- Navigation -->
  <nav class="bg-white border-b border-stone-200 shadow-sm">
    <div class="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
      <div class="flex justify-between h-16 items-center">
        <a href="/" class="flex items-center gap-2 text-brand-700 font-semibold text-lg tracking-tight">
          <svg class="w-6 h-6" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" d="M12 3v1m0 16v1M4.22 4.22l.707.707m12.728 12.728.707.707M3 12h1m16 0h1M4.927 19.073l.707-.707M18.364 5.636l.707-.707" />
          </svg>
          StudioOps
        </a>

        {% if current_user.is_authenticated %}
        <div class="flex items-center gap-6">
          <a href="{{ url_for('booking.index') }}" class="text-sm font-medium text-stone-600 hover:text-brand-700 transition-colors">Schedule</a>
          {% if current_user.role in ['staff', 'admin'] %}
          <a href="{{ url_for('staff.index') }}" class="text-sm font-medium text-stone-600 hover:text-brand-700 transition-colors">Staff</a>
          {% endif %}
          {% if current_user.role in ['editor', 'admin'] %}
          <a href="{{ url_for('content.index') }}" class="text-sm font-medium text-stone-600 hover:text-brand-700 transition-colors">Content</a>
          {% endif %}
          {% if current_user.role == 'admin' %}
          <a href="{{ url_for('admin.index') }}" class="text-sm font-medium text-stone-600 hover:text-brand-700 transition-colors">Admin</a>
          {% endif %}
          <span class="text-sm text-stone-400">|</span>
          <span class="text-sm text-stone-600">{{ current_user.username }}</span>
          <form action="{{ url_for('auth.logout') }}" method="post" class="inline">
            <input type="hidden" name="csrf_token" value="{{ csrf_token() }}" />
            <button type="submit" class="text-sm text-stone-500 hover:text-red-600 transition-colors">Log out</button>
          </form>
        </div>
        {% else %}
        <div class="flex items-center gap-4">
          <a href="{{ url_for('auth.login') }}" class="text-sm font-medium text-stone-600 hover:text-brand-700">Log in</a>
          <a href="{{ url_for('auth.register') }}" class="text-sm font-medium bg-brand-600 text-white px-4 py-2 rounded-lg hover:bg-brand-700 transition-colors">Sign up</a>
        </div>
        {% endif %}
      </div>
    </div>
  </nav>

  <!-- Flash messages (server-side) -->
  <div id="flash-container" class="max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 pt-4">
    {% with messages = get_flashed_messages(with_categories=true) %}
      {% if messages %}
        {% for category, message in messages %}
          {% include "partials/flash.html" %}
        {% endfor %}
      {% endif %}
    {% endwith %}
  </div>

  <!-- Main content -->
  <main class="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8">
    {% block content %}{% endblock %}
  </main>

  <footer class="border-t border-stone-200 mt-auto py-6 text-center text-xs text-stone-400">
    &copy; {{ now.year if now else 2025 }} StudioOps. All rights reserved.
  </footer>

</body>
</html>
"}

