import pytest
from app import create_app
from app.extensions import db as _db
from app.services.auth_service import register_user


@pytest.fixture(scope="function")
def app():
    app = create_app("testing")
    with app.app_context():
        _db.create_all()
        yield app
        _db.session.remove()
        _db.drop_all()


@pytest.fixture
def client(app):
    return app.test_client()


@pytest.fixture
def registered_user(app):
    with app.app_context():
        user, _ = register_user("testuser", "test@example.com", "Password1")
        return user


# ── GET pages render ──────────────────────────────────────────────────────────

class TestAuthPages:
    def test_login_page_renders(self, client):
        resp = client.get("/auth/login")
        assert resp.status_code == 200
        assert b"Log in" in resp.data

    def test_register_page_renders(self, client):
        resp = client.get("/auth/register")
        assert resp.status_code == 200
        assert b"Create" in resp.data

    def test_root_redirects_to_login_when_anonymous(self, client):
        resp = client.get("/", follow_redirects=False)
        assert resp.status_code == 302
        assert "/auth/login" in resp.headers["Location"]


# ── Registration endpoint ─────────────────────────────────────────────────────

class TestRegisterEndpoint:
    def test_successful_registration_redirects(self, client):
        resp = client.post("/auth/register", data={
            "username": "newuser",
            "email": "newuser@example.com",
            "password": "Password1",
            "confirm": "Password1",
        }, follow_redirects=False)
        assert resp.status_code == 302

    def test_mismatched_passwords_returns_form(self, client):
        resp = client.post("/auth/register", data={
            "username": "u1",
            "email": "u1@example.com",
            "password": "Password1",
            "confirm": "Password2",
        })
        assert resp.status_code == 200
        assert b"do not match" in resp.data.lower() or b"match" in resp.data.lower()

    def test_weak_password_returns_422_htmx(self, client):
        resp = client.post("/auth/register",
            data={
                "username": "u2",
                "email": "u2@example.com",
                "password": "weak",
                "confirm": "weak",
            },
            headers={"HX-Request": "true"},
        )
        assert resp.status_code == 422

    def test_duplicate_username_shows_error(self, client, registered_user):
        resp = client.post("/auth/register", data={
            "username": "testuser",
            "email": "other@example.com",
            "password": "Password1",
            "confirm": "Password1",
        })
        assert resp.status_code == 200
        assert b"taken" in resp.data.lower() or b"already" in resp.data.lower()


# ── Login endpoint ────────────────────────────────────────────────────────────

class TestLoginEndpoint:
    def test_valid_login_redirects(self, client, registered_user):
        resp = client.post("/auth/login", data={
            "identifier": "testuser",
            "password": "Password1",
        }, follow_redirects=False)
        assert resp.status_code == 302

    def test_invalid_password_stays_on_login(self, client, registered_user):
        resp = client.post("/auth/login", data={
            "identifier": "testuser",
            "password": "WrongPass1",
        })
        assert resp.status_code == 200
        assert b"Invalid" in resp.data or b"invalid" in resp.data

    def test_htmx_invalid_login_returns_422(self, client, registered_user):
        resp = client.post("/auth/login",
            data={"identifier": "testuser", "password": "WrongPass1"},
            headers={"HX-Request": "true"},
        )
        assert resp.status_code == 422

    def test_htmx_valid_login_returns_hx_redirect(self, client, registered_user):
        resp = client.post("/auth/login",
            data={"identifier": "testuser", "password": "Password1"},
            headers={"HX-Request": "true"},
        )
        assert resp.status_code == 200
        assert "HX-Redirect" in resp.headers

    def test_login_by_email(self, client, registered_user):
        resp = client.post("/auth/login", data={
            "identifier": "test@example.com",
            "password": "Password1",
        }, follow_redirects=False)
        assert resp.status_code == 302

    def test_missing_fields_shows_errors(self, client):
        resp = client.post("/auth/login", data={
            "identifier": "",
            "password": "",
        })
        assert resp.status_code == 200
        assert b"required" in resp.data.lower()


# ── Logout endpoint ───────────────────────────────────────────────────────────

class TestLogoutEndpoint:
    def _login(self, client):
        client.post("/auth/login", data={
            "identifier": "testuser",
            "password": "Password1",
        })

    def test_logout_redirects_to_login(self, client, registered_user):
        self._login(client)
        resp = client.post("/auth/logout", follow_redirects=False)
        assert resp.status_code == 302
        assert "/auth/login" in resp.headers["Location"]

    def test_logout_requires_login(self, client):
        resp = client.post("/auth/logout", follow_redirects=False)
        # Flask-Login redirects unauthenticated users
        assert resp.status_code in (302, 401)


# ── Lockout integration ───────────────────────────────────────────────────────

class TestLockoutIntegration:
    def test_account_locked_after_max_attempts(self, client, registered_user, app):
        max_attempts = app.config["MAX_LOGIN_ATTEMPTS"]
        for _ in range(max_attempts):
            client.post("/auth/login", data={
                "identifier": "testuser",
                "password": "WrongPass1",
            })
        resp = client.post("/auth/login", data={
            "identifier": "testuser",
            "password": "Password1",
        })
        assert resp.status_code == 200
        assert b"locked" in resp.data.lower()
"}

