          {{ s.room_name }} ·
          <span class="{% if s.booked_count >= s.capacity %}text-red-500 font-medium{% else %}text-slate-500{% endif %}">
            {{ s.booked_count }}/{{ s.capacity }}
          </span>
        </p>

        <!-- Actions -->
        <a href="/staff/session/{{ s.session_id }}/roster"
           class="w-full inline-flex items-center justify-center gap-1.5 py-1.5 px-3 text-xs font-medium text-teal-700 bg-teal-50 border border-teal-200 rounded-lg hover:bg-teal-100 transition-colors">
          <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" d="M15 19.128a9.38 9.38 0 002.625.372 9.337 9.337 0 004.121-.952 4.125 4.125 0 00-7.533-2.493M15 19.128v-.003c0-1.113-.285-2.16-.786-3.07M15 19.128v.106A12.318 12.318 0 018.624 21c-2.331 0-4.512-.645-6.374-1.766l-.001-.109a6.375 6.375 0 0111.964-3.07M12 6.375a3.375 3.375 0 11-6.75 0 3.375 3.375 0 016.75 0zm8.25 2.25a2.625 2.625 0 11-5.25 0 2.625 2.625 0 015.25 0z"/>
          </svg>
          View Roster
        </a>
      </div>
      {% endfor %}
    </div>
    {% else %}
    <p class="text-sm text-slate-400 pl-1">No sessions.</p>
    {% endif %}
  </div>
  {% endfor %}
</div>
{% endif %}
"}

